    0.13435305349203377-0.06645010471191085im  -0.03600055518995778+0.03184054754860247im    0.1378319058884279-0.13740564441953115im  0.1646508273778247+0.0im]

# 2 Qubits → 2 Qutrits
# Qubit Basis: |00⟩,|01⟩,|10⟩,|11⟩ (4×4)
# Qutrit Basis: |00⟩,|01⟩,|02⟩,|10⟩,|11⟩,|12⟩,|20⟩,|21⟩,|22⟩ (9×9)
#
# Mapping:
#   Qubit |00⟩ = Index 1 → Qutrit |00⟩ = Index 1
#   Qubit |01⟩ = Index 2 → Qutrit |01⟩ = Index 2
#   Qubit |10⟩ = Index 3 → Qutrit |10⟩ = Index 4
#   Qubit |11⟩ = Index 4 → Qutrit |11⟩ = Index 5

RhoTrue = zeros(ComplexF64, 9, 9)

# Qubit Index → Qutrit Index Mapping
# Qubit |ij⟩ mit i,j ∈ {0,1} → Qutrit |ij⟩ mit i,j ∈ {0,1,2}
# Qutrit Index = i*3 + j + 1  (1-basiert)
# Qubit  Index = i*2 + j + 1  (1-basiert)

qubit_to_qutrit_idx = Dict(
    1 => 1,   # |00⟩ → |00⟩
    2 => 2,   # |01⟩ → |01⟩
    3 => 4,   # |10⟩ → |10⟩
    4 => 5    # |11⟩ → |11⟩
)

for i in 1:4, j in 1:4
    qi = qubit_to_qutrit_idx[i]
    qj = qubit_to_qutrit_idx[j]
    RhoTrue[qi, qj] = rho_qubit[i, j]
end
=#
# ── Rekonstruktionen ───────────────────────────────────────────
println("── Lineare Inversion ──")
RhoRecreatedLI = RecreatingDensityMatrixWithLineareInversionQutrit(
    RhoTrue, nMeasurements)

println("\n── MLE ──")
RhoRecreatedMLE = RecreatingDensityMatrixWithMLEQutrit(
    RhoTrue, nMeasurements)

println("\n── SEEQST NonEntangling ──")
RhoRecreatedNonEnt = RecreatingDensityMatrixWithNonentanglingQutrit(
    RhoTrue, nMeasurements)

println("\n── SEEQST Hybrid ──")
RhoRecreatedHybrid = RecreatingDensityMatrixWithSeeqstQutrit(
    RhoTrue, nMeasurements)

# ── Structs ────────────────────────────────────────────────────
StructLI     = ReconstructedDensityMatrix(Matrix{ComplexF64}(RhoRecreatedLI),     RhoTrue)
StructMLE    = ReconstructedDensityMatrix(Matrix{ComplexF64}(RhoRecreatedMLE),    RhoTrue)
StructNonEnt = ReconstructedDensityMatrix(Matrix{ComplexF64}(RhoRecreatedNonEnt), RhoTrue)
StructHybrid = ReconstructedDensityMatrix(Matrix{ComplexF64}(RhoRecreatedHybrid), RhoTrue)

# ── Ergebnisse ─────────────────────────────────────────────────
println("\n" * "━"^50)
println("Ergebnisse N=$N Qutrits, shots=$nMeasurements")
println("━"^50)
println(@sprintf("%-25s  %-10s  %-10s", "Methode", "Fidelität", "Purity"))
println("─"^50)
println(@sprintf("%-25s  %-10.4f  %-10.4f", "Lineare Inversion",   StructLI.fidelity,     StructLI.purity))
println(@sprintf("%-25s  %-10.4f  %-10.4f", "MLE",                  StructMLE.fidelity,    StructMLE.purity))
println(@sprintf("%-25s  %-10.4f  %-10.4f", "SEEQST NonEntangling", StructNonEnt.fidelity, StructNonEnt.purity))
println(@sprintf("%-25s  %-10.4f  %-10.4f", "SEEQST Hybrid",        StructHybrid.fidelity, StructHybrid.purity))
println("━"^50)


