# ── Shots Liste ────────────────────────────────────────────────
shots_list = 10000:100:100000

# ── Fidelity Listen ────────────────────────────────────────────
fidelities_LI     = Float64[]
fidelities_MLE    = Float64[]
fidelities_Hybrid = Float64[]

# ── Messungen ──────────────────────────────────────────────────
for shots in shots_list
    println("shots = $shots")

    # Lineare Inversion
    rho_li = LineareInversionQutrit.FunctionLinearInversionQutrit(
        RhoTrue, N, shots)
    push!(fidelities_LI, fidelity(Matrix{ComplexF64}(rho_li), RhoTrue))

    # MLE
    rho_mle = QuantumMLEQutrit.RecreatingDensityMatrixWithMLEQutrit(
        RhoTrue, shots)
    push!(fidelities_MLE, fidelity(Matrix{ComplexF64}(rho_mle), RhoTrue))

    # SEEQST Hybrid
    rho_hyb = RecreatingDensityMatrixWithSeeqstQutrit(RhoTrue, shots)
    push!(fidelities_Hybrid, fidelity(Matrix{ComplexF64}(rho_hyb), RhoTrue))
end

# ── Plot 1: Lineare Inversion ──────────────────────────────────
plt1 = plot(collect(shots_list), fidelities_LI,
    xlabel      = "Anzahl Shots",
    ylabel      = "Fidelität",
    title       = "Lineare Inversion (N=3 Qutrits)",
    legend      = false,
    linewidth   = 2,
    color       = :blue,
    titlefontsize = 11)
savefig(plt1, "fidelity_LI_qutrit.png")
display(plt1)

# ── Plot 2: MLE ────────────────────────────────────────────────
plt2 = plot(collect(shots_list), fidelities_MLE,
    xlabel      = "Anzahl Shots",
    ylabel      = "Fidelität",
    title       = "MLE (N=3 Qutrits)",
    legend      = false,
    linewidth   = 2,
    color       = :red,
    titlefontsize = 11)
savefig(plt2, "fidelity_MLE_qutrit.png")
display(plt2)

# ── Plot 3: SEEQST Hybrid ──────────────────────────────────────
plt3 = plot(collect(shots_list), fidelities_Hybrid,
    xlabel      = "Anzahl Shots",
    ylabel      = "Fidelität",
    title       = "SEEQST Hybrid (N=3 Qutrits)",
    legend      = false,
    linewidth   = 2,
    color       = :green,
    titlefontsize = 11)
savefig(plt3, "fidelity_Hybrid_qutrit.png")
display(plt3)

# ── Alle zusammen ──────────────────────────────────────────────
plt4 = plot(collect(shots_list), fidelities_LI,
    label       = "Lineare Inversion",
    xlabel      = "Anzahl Shots",
    ylabel      = "Fidelität",
    title       = "Vergleich N=3 Qutrits",
    linewidth   = 2,
    color       = :blue,
    titlefontsize = 11)
plot!(plt4, collect(shots_list), fidelities_MLE,
    label     = "MLE",
    linewidth = 2,
    color     = :red)
plot!(plt4, collect(shots_list), fidelities_Hybrid,
    label     = "SEEQST Hybrid",
    linewidth = 2,
    color     = :green)
savefig(plt4, "fidelity_Vergleich_qutrit.png")
display(plt4)

println("\n✓ Plots gespeichert")
